import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku } from '@sudoku/sudoku';
import { gameSession } from '../../../game-session.js';
import { hints } from './hints';

export const currentGame = {
	subscribe: gameSession.gameStore.subscribe,

	resetWithPuzzle(nextPuzzle) {
		gameSession.start(nextPuzzle);
	},

	loadFromJSON(json) {
		gameSession.load(json);
	},

	guess(move) {
		gameSession.guess(move);
	},

	undo() {
		gameSession.undo();
	},

	redo() {
		gameSession.redo();
	},

	startExplore() {
		return gameSession.startExplore();
	},

	commitExplore() {
		return gameSession.commitExplore();
	},

	discardExplore() {
		return gameSession.discardExplore();
	},

	canUndo() {
		return gameSession.canUndo();
	},

	canRedo() {
		return gameSession.canRedo();
	},

	toJSON() {
		return gameSession.exportJSON();
	},

	toString() {
		return gameSession.toString();
	},
};

export const grid = {
	subscribe: gameSession.initialGridStore.subscribe,

	generate(difficulty) {
		gameSession.start(generateSudoku(difficulty));
	},

	decodeSencode(sencode) {
		gameSession.start(decodeSencode(sencode));
	},

	get(gridStore, x, y) {
		return gridStore[y][x];
	},

	getSencode(gridStore) {
		return encodeSudoku(gridStore);
	},
};

export const userGrid = {
	subscribe(run) {
		return gameSession.currentGridStore.subscribe(run);
	},

	set(pos, value) {
		return gameSession.guess({
			row: pos.y,
			col: pos.x,
			value,
		});
	},

	applyHint(pos) {
		if (pos.x === null || pos.y === null) {
			return null;
		}

		const currentGrid = gameSession.getCurrentGrid();
		if (currentGrid[pos.y][pos.x] !== 0) {
			return null;
		}

		const hint = gameSession.getCandidateHint(pos.y, pos.x);
		if (hint.candidates.length > 0) {
			hints.useHint();
		}

		return hint;
	},

	applyNextHint() {
		const hint = gameSession.applyNextHint();
		if (hint) {
			hints.useHint();
		}

		return hint;
	},
};

export const invalidCells = {
	subscribe: gameSession.invalidCellsStore.subscribe,
};

export const exploreState = {
	subscribe: gameSession.exploreStateStore.subscribe,
};
